import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Bar } from 'react-chartjs-2';
import 'chart.js/auto';
import api, { apiBaseUrl } from './api';
import { isAdmin, readUser } from './constants';

function groupCount(items, key) {
  const map = new Map();

  items.forEach((item) => {
    const value = key(item) || 'Não informado';
    map.set(value, (map.get(value) || 0) + 1);
  });

  return Array.from(map.entries())
    .map(([label, total]) => ({ label, total }))
    .sort((a, b) => b.total - a.total);
}

function chartData(rows, color = '#0b6f5f') {
  return {
    labels: rows.map((row) => row.label),
    datasets: [{
      label: 'Reclamações',
      data: rows.map((row) => row.total),
      backgroundColor: color,
      borderRadius: 6
    }]
  };
}

const chartOptions = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: {
      display: false
    }
  }
};

function BI() {
  const navigate = useNavigate();
  const user = readUser();
  const [rows, setRows] = useState([]);
  const [feedback, setFeedback] = useState('');
  const canAccess = isAdmin(user);

  useEffect(() => {
    if (!canAccess) return;

    api.get('/bi/complaints')
      .then((res) => setRows(Array.isArray(res.data) ? res.data : []))
      .catch(() => setFeedback('Não foi possível carregar os dados de BI.'));
  }, [canAccess]);

  const byType = useMemo(() => groupCount(rows, (item) => item.complaint_type).slice(0, 10), [rows]);
  const byRegion = useMemo(() => groupCount(rows, (item) => item.region).slice(0, 10), [rows]);
  const byState = useMemo(() => groupCount(rows, (item) => item.state).slice(0, 10), [rows]);
  const endpoint = `${apiBaseUrl}/bi/complaints`;

  if (!canAccess) {
    return (
      <main className="app-page">
        <section className="restricted-panel">
          <p className="eyebrow">Acesso restrito</p>
          <h1>BI administrativo</h1>
          <p>Esta área é exclusiva para administradores.</p>
          <button className="primary-action" onClick={() => navigate('/home')}>
            Voltar para Home
          </button>
        </section>
      </main>
    );
  }

  return (
    <main className="app-page">
      <header className="page-heading">
        <div>
          <p className="eyebrow">BI administrador</p>
          <h1>Base analítica de reclamações</h1>
          <p>Use esta tela para análise executiva ou conecte o Power BI pelo endpoint Web.</p>
        </div>

        <button className="outline-action" onClick={() => navigate('/home')}>
          Home
        </button>
      </header>

      <section className="bi-endpoint">
        <div>
          <span>Endpoint para Power BI</span>
          <strong>{endpoint}</strong>
        </div>
        <p>No Power BI Desktop, use Obter Dados &gt; Web e envie o header Authorization com o token do administrador.</p>
      </section>

      {feedback && <p className="form-feedback">{feedback}</p>}

      <section className="chart-grid">
        <article className="chart-card">
          <h2>Tipos mais recorrentes</h2>
          <div className="chart-box">
            <Bar data={chartData(byType)} options={chartOptions} />
          </div>
        </article>

        <article className="chart-card">
          <h2>Volume por região</h2>
          <div className="chart-box">
            <Bar data={chartData(byRegion, '#1f7a8c')} options={chartOptions} />
          </div>
        </article>

        <article className="chart-card">
          <h2>Volume por estado</h2>
          <div className="chart-box">
            <Bar data={chartData(byState, '#4c956c')} options={chartOptions} />
          </div>
        </article>
      </section>

      <section className="management-panel">
        <div className="panel-heading">
          <div>
            <p className="eyebrow">Prévia da base</p>
            <h2>{rows.length} registros disponíveis</h2>
          </div>
        </div>

        <div className="data-table-wrap">
          <table className="data-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Clínica</th>
                <th>Tipo</th>
                <th>Status</th>
                <th>Cidade</th>
                <th>Estado</th>
                <th>Região</th>
              </tr>
            </thead>
            <tbody>
              {rows.slice(0, 25).map((item) => (
                <tr key={item.id}>
                  <td>{item.id}</td>
                  <td>{item.clinic_name}</td>
                  <td>{item.complaint_type}</td>
                  <td>{item.status}</td>
                  <td>{item.city}</td>
                  <td>{item.state}</td>
                  <td>{item.region}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </main>
  );
}

export default BI;
